+    auto coord = builder.add(ir::Op::IAdd(ir::BasicType(ir::ScalarType::eU32, coordDims),
+      helper.emitExtractVector(builder, coordOffset, 0u, coordDims),
+      helper.emitExtractVector(builder, compute.globalId, 0u, coordDims)));
