commit ef62cd9f689126c7d721f0eb19a4695d8a6bdc64
Author: Philip Rebohle <philip.rebohle@tu-dortmund.de>
Date:   Tue Feb 24 22:21:56 2026 +0100

    [dxvk] Fix graphics resource synchronization (again)

    Same issue that Deadlock ran into, except this time with index and
    vertex buffers. We need to mark those as dirty when written by an
    external source before a render pass so that they get checked again.

    As a shortcut, skip any checks if the pending barriers do not include
    the relevant access masks. This is especially useful to not uselessly
    iterate over vertex buffers when only an image has been written, etc.
---
 src/dxvk/dxvk_context.cpp | 52 ++++++++++++++++++++++++++++++-----------------
 1 file changed, 33 insertions(+), 19 deletions(-)

diff --git a/src/dxvk/dxvk_context.cpp b/src/dxvk/dxvk_context.cpp
index 5df7058d..10c90493 100644
--- a/src/dxvk/dxvk_context.cpp
+++ b/src/dxvk/dxvk_context.cpp
@@ -7503,7 +7503,8 @@ namespace dxvk {


   void DxvkContext::beginComputePass() {
-    m_flags.set(DxvkContextFlag::CpComputePassActive);
+    m_flags.set(DxvkContextFlag::CpComputePassActive,
+                DxvkContextFlag::DirtyDrawBuffer);

     // Mark compute descriptors as dirty so that hazards are checked properly
     // between dispatches even when none of the resources were re-bound. This
@@ -7607,18 +7608,22 @@ namespace dxvk {
     }

     // Check whether we can actually start the render pass as unsynchronized.
-    if (!m_flags.any(DxvkContextFlag::GpRenderPassActive)) {
+    if (!m_flags.test(DxvkContextFlag::GpRenderPassActive)) {
       if (renderPassStartUnsynchronized()) {
         m_flags.set(DxvkContextFlag::GpRenderPassUnsynchronized);
         m_unsynchronizedDrawCount = 0u;
       }

