+vec4 readArgValue(uint stage, uint arg, vec4 current, vec4 temp, vec4 textureVal) {
+    vec4 reg = vec4(1.0);
+    switch (arg & D3DTA_SELECTMASK) {
+        case D3DTA_CONSTANT:
+            reg = vec4(
+                sharedData.Stages[stage].Constant[0],
+                sharedData.Stages[stage].Constant[1],
+                sharedData.Stages[stage].Constant[2],
+                sharedData.Stages[stage].Constant[3]
+            );
+            break;
+        case D3DTA_CURRENT:
+            reg = current;
+            break;
+        case D3DTA_DIFFUSE:
+            reg = in_Color0;
+            break;
+        case D3DTA_SPECULAR:
+            reg = in_Color1;
+            break;
+        case D3DTA_TEMP:
+            reg = temp;
+            break;
+        case D3DTA_TEXTURE:
+            reg = textureVal;
+            break;
+        case D3DTA_TFACTOR:
+            reg = data.textureFactor;
+            break;
+    }
+
+    // reg = 1 - reg
+    if ((arg & D3DTA_COMPLEMENT) != 0)
+        reg = vec4(1.0) - reg;
+
+    // reg = reg.wwww
+    if ((arg & D3DTA_ALPHAREPLICATE) != 0)
+        reg = reg.aaaa;
+
+    return reg;
+}
