+          int32_t                   toleranceUs,
+          bool                      useNvLowLatency2)
+  : m_presenter(std::move(presenter)),
+    m_tolerance(std::chrono::duration_cast<duration>(
+      std::chrono::microseconds(std::max(toleranceUs, 0)))),
+    m_useNvLowLatency2(useNvLowLatency2) {
